  service: AnalyticsService,
  params: { preset?: string; startDate?: string; endDate?: string; limit?: number },
): Promise<AnalyticsResponse<TopProduct[] | null>> {
  const queryOrError = parseQueryParams(params);
  if (typeof queryOrError === 'string') {
    return { success: false, data: null, error: queryOrError };
  }

  const range = queryOrError.range ?? {
    start: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
    end: new Date(),
  };
  const limit = params.limit && params.limit > 0 ? params.limit : 10;
  const data = await service.getTopProducts(range, limit);
  return { success: true, data };
}

